using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve EF Core 8 id format ("Product|123") so existing 500K documents remain readable.
        // Without this, EF Core 9 generates ids as just "123" and won't find old documents.
        optionsBuilder.UseCosmos(o =>
        {
            // Connection config is expected from the caller / config system
        });
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasIndex() now throws for Cosmos — removed.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            // Revert to the EF8 property name for backward compatibility.
            entity.HasDiscriminant("Discriminator");

            // EF Core 9 breaking change: id values no longer include the entity type prefix.
            // EF8 wrote ids as "Product|123"; EF9 defaults to just "123".
            // Existing documents won't be found without this opt-in.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");

            // Preserve the "Product|123" id format for 500K existing documents.
            entity.UseETagConcurrency();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Preserve EF8-style "EntityName|Key" id format for all entities
        configurationBuilder.Conventions.Add(_ => new IdFormatConvention());
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

