class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    // EF Core 9 breaking change: synchronous APIs (ToList, First, etc.) removed for Cosmos.
    // All queries must be async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (safe because we
        // configured HasDiscriminant("Discriminator") to preserve the EF8 property name).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Migrated from sync .ToList() to async .ToListAsync()
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

