            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents store "Discriminator"; direct SQL queries use c.Discriminator.
            // Restore the EF8 property name so old documents are readable without migration.
            entity.HasDiscriminator<string>("Discriminator");

