using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.Metadata;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // REMOVED: HasIndex() — EF Core 9 now throws for Cosmos (indexes are managed server-side).

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents store "Discriminator"; direct SQL queries use c.Discriminator.
            // Restore the EF8 property name so old documents are readable without migration.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Document id format changed from "Product|123" to just "123".
            // Existing documents use the old format. Override the __id shadow property's value
            // generator to keep producing "EntityType|Key" ids matching the 500K existing docs.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyIdValueGenerator>();
        });
    }
}

/// <summary>
/// Generates Cosmos document ids in the EF Core 8 format: "EntityTypeName|KeyValue"
/// so new writes remain compatible with the 500K existing documents.
/// </summary>
class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var typeName = entry.Metadata.ClrType.Name;
        var key = entry.Property("Id").CurrentValue;
        return $"{typeName}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = "";
}

